(function() {
    var type_impls = Object.fromEntries([["zeroclaw_tools",[["<details class=\"toggle implementors-toggle\" open><summary><section id=\"impl-AsMut%3CT%3E-for-Session%3CT%3E\" class=\"impl\"><a href=\"#impl-AsMut%3CT%3E-for-Session%3CT%3E\" class=\"anchor\">§</a><h3 class=\"code-header\">impl&lt;T&gt; <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsMut.html\" title=\"trait core::convert::AsMut\">AsMut</a>&lt;T&gt; for Session&lt;T&gt;<div class=\"where\">where\n    T: AsyncRead + AsyncWrite + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/marker/trait.Unpin.html\" title=\"trait core::marker::Unpin\">Unpin</a> + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/fmt/trait.Debug.html\" title=\"trait core::fmt::Debug\">Debug</a>,</div></h3></section></summary><div class=\"impl-items\"><details class=\"toggle method-toggle\" open><summary><section id=\"method.as_mut\" class=\"method trait-impl\"><a href=\"#method.as_mut\" class=\"anchor\">§</a><h4 class=\"code-header\">fn <a href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsMut.html#tymethod.as_mut\" class=\"fn\">as_mut</a>(&amp;mut self) -&gt; <a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.reference.html\">&amp;mut T</a></h4></section></summary><div class='docblock'>Converts this type into a mutable reference of the (usually inferred) input type.</div></details></div></details>","AsMut<T>","zeroclaw_tools::email_imap::ImapSession"],["<details class=\"toggle implementors-toggle\" open><summary><section id=\"impl-Debug-for-Session%3CT%3E\" class=\"impl\"><a href=\"#impl-Debug-for-Session%3CT%3E\" class=\"anchor\">§</a><h3 class=\"code-header\">impl&lt;T&gt; <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/fmt/trait.Debug.html\" title=\"trait core::fmt::Debug\">Debug</a> for Session&lt;T&gt;<div class=\"where\">where\n    T: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/fmt/trait.Debug.html\" title=\"trait core::fmt::Debug\">Debug</a> + AsyncRead + AsyncWrite + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/marker/trait.Unpin.html\" title=\"trait core::marker::Unpin\">Unpin</a>,</div></h3></section></summary><div class=\"impl-items\"><details class=\"toggle method-toggle\" open><summary><section id=\"method.fmt\" class=\"method trait-impl\"><a href=\"#method.fmt\" class=\"anchor\">§</a><h4 class=\"code-header\">fn <a href=\"https://doc.rust-lang.org/1.96.1/core/fmt/trait.Debug.html#tymethod.fmt\" class=\"fn\">fmt</a>(&amp;self, f: &amp;mut <a class=\"struct\" href=\"https://doc.rust-lang.org/1.96.1/core/fmt/struct.Formatter.html\" title=\"struct core::fmt::Formatter\">Formatter</a>&lt;'_&gt;) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.unit.html\">()</a>, <a class=\"struct\" href=\"https://doc.rust-lang.org/1.96.1/core/fmt/struct.Error.html\" title=\"struct core::fmt::Error\">Error</a>&gt;</h4></section></summary><div class='docblock'>Formats the value using the given formatter. <a href=\"https://doc.rust-lang.org/1.96.1/core/fmt/trait.Debug.html#tymethod.fmt\">Read more</a></div></details></div></details>","Debug","zeroclaw_tools::email_imap::ImapSession"],["<details class=\"toggle implementors-toggle\" open><summary><section id=\"impl-Deref-for-Session%3CT%3E\" class=\"impl\"><a href=\"#impl-Deref-for-Session%3CT%3E\" class=\"anchor\">§</a><h3 class=\"code-header\">impl&lt;T&gt; <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/ops/deref/trait.Deref.html\" title=\"trait core::ops::deref::Deref\">Deref</a> for Session&lt;T&gt;<div class=\"where\">where\n    T: AsyncRead + AsyncWrite + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/marker/trait.Unpin.html\" title=\"trait core::marker::Unpin\">Unpin</a> + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/fmt/trait.Debug.html\" title=\"trait core::fmt::Debug\">Debug</a>,</div></h3></section></summary><div class=\"impl-items\"><details class=\"toggle\" open><summary><section id=\"associatedtype.Target\" class=\"associatedtype trait-impl\"><a href=\"#associatedtype.Target\" class=\"anchor\">§</a><h4 class=\"code-header\">type <a href=\"https://doc.rust-lang.org/1.96.1/core/ops/deref/trait.Deref.html#associatedtype.Target\" class=\"associatedtype\">Target</a> = Connection&lt;T&gt;</h4></section></summary><div class='docblock'>The resulting type after dereferencing.</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.deref\" class=\"method trait-impl\"><a href=\"#method.deref\" class=\"anchor\">§</a><h4 class=\"code-header\">fn <a href=\"https://doc.rust-lang.org/1.96.1/core/ops/deref/trait.Deref.html#tymethod.deref\" class=\"fn\">deref</a>(&amp;self) -&gt; &amp;Connection&lt;T&gt;</h4></section></summary><div class='docblock'>Dereferences the value.</div></details></div></details>","Deref","zeroclaw_tools::email_imap::ImapSession"],["<details class=\"toggle implementors-toggle\" open><summary><section id=\"impl-DerefMut-for-Session%3CT%3E\" class=\"impl\"><a href=\"#impl-DerefMut-for-Session%3CT%3E\" class=\"anchor\">§</a><h3 class=\"code-header\">impl&lt;T&gt; <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/ops/deref/trait.DerefMut.html\" title=\"trait core::ops::deref::DerefMut\">DerefMut</a> for Session&lt;T&gt;<div class=\"where\">where\n    T: AsyncRead + AsyncWrite + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/marker/trait.Unpin.html\" title=\"trait core::marker::Unpin\">Unpin</a> + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/fmt/trait.Debug.html\" title=\"trait core::fmt::Debug\">Debug</a>,</div></h3></section></summary><div class=\"impl-items\"><details class=\"toggle method-toggle\" open><summary><section id=\"method.deref_mut\" class=\"method trait-impl\"><a href=\"#method.deref_mut\" class=\"anchor\">§</a><h4 class=\"code-header\">fn <a href=\"https://doc.rust-lang.org/1.96.1/core/ops/deref/trait.DerefMut.html#tymethod.deref_mut\" class=\"fn\">deref_mut</a>(&amp;mut self) -&gt; &amp;mut Connection&lt;T&gt;</h4></section></summary><div class='docblock'>Mutably dereferences the value.</div></details></div></details>","DerefMut","zeroclaw_tools::email_imap::ImapSession"],["<details class=\"toggle implementors-toggle\" open><summary><section id=\"impl-Session%3CT%3E\" class=\"impl\"><a href=\"#impl-Session%3CT%3E\" class=\"anchor\">§</a><h3 class=\"code-header\">impl&lt;T&gt; Session&lt;T&gt;<div class=\"where\">where\n    T: AsyncRead + AsyncWrite + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/marker/trait.Unpin.html\" title=\"trait core::marker::Unpin\">Unpin</a> + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/fmt/trait.Debug.html\" title=\"trait core::fmt::Debug\">Debug</a> + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/marker/trait.Send.html\" title=\"trait core::marker::Send\">Send</a>,</div></h3></section></summary><div class=\"impl-items\"><details class=\"toggle method-toggle\" open><summary><section id=\"method.select\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.select\" class=\"fn\">select</a>&lt;S&gt;(&amp;mut self, mailbox_name: S) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;Mailbox, Error&gt;<div class=\"where\">where\n    S: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>Selects a mailbox.</p>\n<p>The <code>SELECT</code> command selects a mailbox so that messages in the mailbox can be accessed.\nNote that earlier versions of this protocol only required the FLAGS, EXISTS, and RECENT\nuntagged data; consequently, client implementations SHOULD implement default behavior for\nmissing data as discussed with the individual item.</p>\n<p>Only one mailbox can be selected at a time in a connection; simultaneous access to multiple\nmailboxes requires multiple connections.  The <code>SELECT</code> command automatically deselects any\ncurrently selected mailbox before attempting the new selection. Consequently, if a mailbox\nis selected and a <code>SELECT</code> command that fails is attempted, no mailbox is selected.</p>\n<p>Note that the server <em>is</em> allowed to unilaterally send things to the client for messages in\na selected mailbox whose status has changed. See the note on <a href=\"https://tools.ietf.org/html/rfc3501#section-7\">unilateral server responses\nin RFC 3501</a>. This means that if run commands,\nyou <em>may</em> see additional untagged <code>RECENT</code>, <code>EXISTS</code>, <code>FETCH</code>, and <code>EXPUNGE</code> responses.\nYou can get them from the <code>unsolicited_responses</code> channel of the <a href=\"struct.Session.html\"><code>Session</code></a>.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.select_condstore\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.select_condstore\" class=\"fn\">select_condstore</a>&lt;S&gt;(\n    &amp;mut self,\n    mailbox_name: S,\n) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;Mailbox, Error&gt;<div class=\"where\">where\n    S: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>Selects a mailbox with <code>(CONDSTORE)</code> parameter as defined in\n<a href=\"https://www.rfc-editor.org/rfc/rfc7162.html#section-3.1.8\">RFC 7162</a>.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.examine\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.examine\" class=\"fn\">examine</a>&lt;S&gt;(&amp;mut self, mailbox_name: S) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;Mailbox, Error&gt;<div class=\"where\">where\n    S: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>The <code>EXAMINE</code> command is identical to [<code>Session::select</code>] and returns the same output;\nhowever, the selected mailbox is identified as read-only. No changes to the permanent state\nof the mailbox, including per-user state, will happen in a mailbox opened with <code>examine</code>;\nin particular, messagess cannot lose [<code>Flag::Recent</code>] in an examined mailbox.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.fetch\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.fetch\" class=\"fn\">fetch</a>&lt;S1, S2&gt;(\n    &amp;mut self,\n    sequence_set: S1,\n    query: S2,\n) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;impl Stream&lt;Item = <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;Fetch, Error&gt;&gt; + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/marker/trait.Send.html\" title=\"trait core::marker::Send\">Send</a>, Error&gt;<div class=\"where\">where\n    S1: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,\n    S2: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>Fetch retreives data associated with a set of messages in the mailbox.</p>\n<p>Note that the server <em>is</em> allowed to unilaterally include <code>FETCH</code> responses for other\nmessages in the selected mailbox whose status has changed. See the note on <a href=\"https://tools.ietf.org/html/rfc3501#section-7\">unilateral\nserver responses in RFC 3501</a>.</p>\n<p><code>query</code> is a list of “data items” (space-separated in parentheses if <code>&gt;1</code>). There are three\n“macro items” which specify commonly-used sets of data items, and can be used instead of\ndata items.  A macro must be used by itself, and not in conjunction with other macros or\ndata items. They are:</p>\n<ul>\n<li><code>ALL</code>: equivalent to: <code>(FLAGS INTERNALDATE RFC822.SIZE ENVELOPE)</code></li>\n<li><code>FAST</code>: equivalent to: <code>(FLAGS INTERNALDATE RFC822.SIZE)</code></li>\n</ul>\n<p>The currently defined data items that can be fetched are listen <a href=\"https://tools.ietf.org/html/rfc3501#section-6.4.5\">in the\nRFC</a>, but here are some common ones:</p>\n<ul>\n<li>\n<p><code>FLAGS</code>: The flags that are set for this message.</p>\n</li>\n<li>\n<p><code>INTERNALDATE</code>: The internal date of the message.</p>\n</li>\n<li>\n<p><code>BODY[&lt;section&gt;]</code>:</p>\n<p>The text of a particular body section.  The section specification is a set of zero or\nmore part specifiers delimited by periods.  A part specifier is either a part number\n(see RFC) or one of the following: <code>HEADER</code>, <code>HEADER.FIELDS</code>, <code>HEADER.FIELDS.NOT</code>,\n<code>MIME</code>, and <code>TEXT</code>.  An empty section specification (i.e., <code>BODY[]</code>) refers to the\nentire message, including the header.</p>\n<p>The <code>HEADER</code>, <code>HEADER.FIELDS</code>, and <code>HEADER.FIELDS.NOT</code> part specifiers refer to the\n<a href=\"https://tools.ietf.org/html/rfc2822\">RFC-2822</a> header of the message or of an\nencapsulated <a href=\"https://tools.ietf.org/html/rfc2046\">MIME-IMT</a>\nMESSAGE/<a href=\"https://tools.ietf.org/html/rfc822\">RFC822</a> message. <code>HEADER.FIELDS</code> and\n<code>HEADER.FIELDS.NOT</code> are followed by a list of field-name (as defined in\n<a href=\"https://tools.ietf.org/html/rfc2822\">RFC-2822</a>) names, and return a subset of the\nheader.  The subset returned by <code>HEADER.FIELDS</code> contains only those header fields with\na field-name that matches one of the names in the list; similarly, the subset returned\nby <code>HEADER.FIELDS.NOT</code> contains only the header fields with a non-matching field-name.\nThe field-matching is case-insensitive but otherwise exact.  Subsetting does not\nexclude the <a href=\"https://tools.ietf.org/html/rfc2822\">RFC-2822</a> delimiting blank line\nbetween the header and the body; the blank line is included in all header fetches,\nexcept in the case of a message which has no body and no blank line.</p>\n<p>The <code>MIME</code> part specifier refers to the <a href=\"https://tools.ietf.org/html/rfc2045\">MIME-IMB</a>\nheader for this part.</p>\n<p>The <code>TEXT</code> part specifier refers to the text body of the message,\nomitting the <a href=\"https://tools.ietf.org/html/rfc2822\">RFC-2822</a> header.</p>\n<p>[<code>Flag::Seen</code>] is implicitly set when <code>BODY</code> is fetched; if this causes the flags to\nchange, they will generally be included as part of the <code>FETCH</code> responses.</p>\n</li>\n<li>\n<p><code>BODY.PEEK[&lt;section&gt;]</code>: An alternate form of <code>BODY[&lt;section&gt;]</code> that does not implicitly\nset [<code>Flag::Seen</code>].</p>\n</li>\n<li>\n<p><code>ENVELOPE</code>: The envelope structure of the message.  This is computed by the server by\nparsing the <a href=\"https://tools.ietf.org/html/rfc2822\">RFC-2822</a> header into the component\nparts, defaulting various fields as necessary.</p>\n</li>\n<li>\n<p><code>RFC822</code>: Functionally equivalent to <code>BODY[]</code>.</p>\n</li>\n<li>\n<p><code>RFC822.HEADER</code>: Functionally equivalent to <code>BODY.PEEK[HEADER]</code>.</p>\n</li>\n<li>\n<p><code>RFC822.SIZE</code>: The <a href=\"https://tools.ietf.org/html/rfc2822\">RFC-2822</a> size of the message.</p>\n</li>\n<li>\n<p><code>UID</code>: The unique identifier for the message.</p>\n</li>\n</ul>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.uid_fetch\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.uid_fetch\" class=\"fn\">uid_fetch</a>&lt;S1, S2&gt;(\n    &amp;mut self,\n    uid_set: S1,\n    query: S2,\n) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;impl Stream&lt;Item = <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;Fetch, Error&gt;&gt; + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/marker/trait.Send.html\" title=\"trait core::marker::Send\">Send</a> + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/marker/trait.Unpin.html\" title=\"trait core::marker::Unpin\">Unpin</a>, Error&gt;<div class=\"where\">where\n    S1: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,\n    S2: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>Equivalent to [<code>Session::fetch</code>], except that all identifiers in <code>uid_set</code> are\n[<code>Uid</code>]s. See also the <a href=\"https://tools.ietf.org/html/rfc3501#section-6.4.8\"><code>UID</code> command</a>.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.noop\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.noop\" class=\"fn\">noop</a>(&amp;mut self) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.unit.html\">()</a>, Error&gt;</h4></section></summary><div class=\"docblock\"><p>Noop always succeeds, and it does nothing.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.logout\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.logout\" class=\"fn\">logout</a>(&amp;mut self) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.unit.html\">()</a>, Error&gt;</h4></section></summary><div class=\"docblock\"><p>Logout informs the server that the client is done with the connection.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.create\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.create\" class=\"fn\">create</a>&lt;S&gt;(&amp;mut self, mailbox_name: S) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.unit.html\">()</a>, Error&gt;<div class=\"where\">where\n    S: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc3501#section-6.3.3\"><code>CREATE</code> command</a> creates a mailbox\nwith the given name.  <code>Ok</code> is returned only if a new mailbox with that name has been\ncreated.  It is an error to attempt to create <code>INBOX</code> or a mailbox with a name that\nrefers to an extant mailbox.  Any error in creation will return [<code>Error::No</code>].</p>\n<p>If the mailbox name is suffixed with the server’s hierarchy separator character (as\nreturned from the server by [<code>Session::list</code>]), this is a declaration that the client\nintends to create mailbox names under this name in the hierarchy.  Servers that do not\nrequire this declaration will ignore the declaration.  In any case, the name created is\nwithout the trailing hierarchy delimiter.</p>\n<p>If the server’s hierarchy separator character appears elsewhere in the name, the server\nwill generally create any superior hierarchical names that are needed for the <code>CREATE</code>\ncommand to be successfully completed.  In other words, an attempt to create <code>foo/bar/zap</code>\non a server in which <code>/</code> is the hierarchy separator character will usually create <code>foo/</code>\nand <code>foo/bar/</code> if they do not already exist.</p>\n<p>If a new mailbox is created with the same name as a mailbox which was deleted, its unique\nidentifiers will be greater than any unique identifiers used in the previous incarnation of\nthe mailbox UNLESS the new incarnation has a different unique identifier validity value.\nSee the description of the <a href=\"https://tools.ietf.org/html/rfc3501#section-6.4.8\"><code>UID</code>\ncommand</a> for more detail.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.delete\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.delete\" class=\"fn\">delete</a>&lt;S&gt;(&amp;mut self, mailbox_name: S) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.unit.html\">()</a>, Error&gt;<div class=\"where\">where\n    S: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc3501#section-6.3.4\"><code>DELETE</code> command</a> permanently\nremoves the mailbox with the given name.  <code>Ok</code> is returned only if the mailbox has been\ndeleted.  It is an error to attempt to delete <code>INBOX</code> or a mailbox name that does not\nexist.</p>\n<p>The <code>DELETE</code> command will not remove inferior hierarchical names. For example, if a mailbox\n<code>foo</code> has an inferior <code>foo.bar</code> (assuming <code>.</code> is the hierarchy delimiter character),\nremoving <code>foo</code> will not remove <code>foo.bar</code>.  It is an error to attempt to delete a name that\nhas inferior hierarchical names and also has [<code>NameAttribute::NoSelect</code>].</p>\n<p>It is permitted to delete a name that has inferior hierarchical names and does not have\n[<code>NameAttribute::NoSelect</code>].  In this case, all messages in that mailbox are removed, and\nthe name will acquire [<code>NameAttribute::NoSelect</code>].</p>\n<p>The value of the highest-used unique identifier of the deleted mailbox will be preserved so\nthat a new mailbox created with the same name will not reuse the identifiers of the former\nincarnation, UNLESS the new incarnation has a different unique identifier validity value.\nSee the description of the <a href=\"https://tools.ietf.org/html/rfc3501#section-6.4.8\"><code>UID</code>\ncommand</a> for more detail.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.rename\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.rename\" class=\"fn\">rename</a>&lt;S1, S2&gt;(&amp;mut self, from: S1, to: S2) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.unit.html\">()</a>, Error&gt;<div class=\"where\">where\n    S1: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,\n    S2: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc3501#section-6.3.5\"><code>RENAME</code> command</a> changes the name\nof a mailbox.  <code>Ok</code> is returned only if the mailbox has been renamed.  It is an error to\nattempt to rename from a mailbox name that does not exist or to a mailbox name that already\nexists.  Any error in renaming will return [<code>Error::No</code>].</p>\n<p>If the name has inferior hierarchical names, then the inferior hierarchical names will also\nbe renamed.  For example, a rename of <code>foo</code> to <code>zap</code> will rename <code>foo/bar</code> (assuming <code>/</code> is\nthe hierarchy delimiter character) to <code>zap/bar</code>.</p>\n<p>If the server’s hierarchy separator character appears in the name, the server will\ngenerally create any superior hierarchical names that are needed for the <code>RENAME</code> command\nto complete successfully.  In other words, an attempt to rename <code>foo/bar/zap</code> to\n<code>baz/rag/zowie</code> on a server in which <code>/</code> is the hierarchy separator character will\ngenerally create <code>baz/</code> and <code>baz/rag/</code> if they do not already exist.</p>\n<p>The value of the highest-used unique identifier of the old mailbox name will be preserved\nso that a new mailbox created with the same name will not reuse the identifiers of the\nformer incarnation, UNLESS the new incarnation has a different unique identifier validity\nvalue. See the description of the <a href=\"https://tools.ietf.org/html/rfc3501#section-6.4.8\"><code>UID</code>\ncommand</a> for more detail.</p>\n<p>Renaming <code>INBOX</code> is permitted, and has special behavior.  It moves all messages in <code>INBOX</code>\nto a new mailbox with the given name, leaving <code>INBOX</code> empty.  If the server implementation\nsupports inferior hierarchical names of <code>INBOX</code>, these are unaffected by a rename of\n<code>INBOX</code>.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.subscribe\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.subscribe\" class=\"fn\">subscribe</a>&lt;S&gt;(&amp;mut self, mailbox: S) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.unit.html\">()</a>, Error&gt;<div class=\"where\">where\n    S: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc3501#section-6.3.6\"><code>SUBSCRIBE</code> command</a> adds the\nspecified mailbox name to the server’s set of “active” or “subscribed” mailboxes as\nreturned by [<code>Session::lsub</code>].  This command returns <code>Ok</code> only if the subscription is\nsuccessful.</p>\n<p>The server may validate the mailbox argument to <code>SUBSCRIBE</code> to verify that it exists.\nHowever, it will not unilaterally remove an existing mailbox name from the subscription\nlist even if a mailbox by that name no longer exists.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.unsubscribe\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.unsubscribe\" class=\"fn\">unsubscribe</a>&lt;S&gt;(&amp;mut self, mailbox: S) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.unit.html\">()</a>, Error&gt;<div class=\"where\">where\n    S: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc3501#section-6.3.7\"><code>UNSUBSCRIBE</code> command</a> removes the\nspecified mailbox name from the server’s set of “active” or “subscribed” mailboxes as\nreturned by [<code>Session::lsub</code>].  This command returns <code>Ok</code> only if the unsubscription is\nsuccessful.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.capabilities\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.capabilities\" class=\"fn\">capabilities</a>(&amp;mut self) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;Capabilities, Error&gt;</h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc3501#section-6.1.1\"><code>CAPABILITY</code> command</a> requests a\nlisting of capabilities that the server supports.  The server will include “IMAP4rev1” as\none of the listed capabilities. See [<code>Capabilities</code>] for further details.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.expunge\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.expunge\" class=\"fn\">expunge</a>(\n    &amp;mut self,\n) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;impl Stream&lt;Item = <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.u32.html\">u32</a>, Error&gt;&gt; + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/marker/trait.Send.html\" title=\"trait core::marker::Send\">Send</a>, Error&gt;</h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc3501#section-6.4.3\"><code>EXPUNGE</code> command</a> permanently\nremoves all messages that have [<code>Flag::Deleted</code>] set from the currently selected mailbox.\nThe message sequence number of each message that is removed is returned.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.uid_expunge\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.uid_expunge\" class=\"fn\">uid_expunge</a>&lt;S&gt;(\n    &amp;mut self,\n    uid_set: S,\n) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;impl Stream&lt;Item = <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.u32.html\">u32</a>, Error&gt;&gt; + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/marker/trait.Send.html\" title=\"trait core::marker::Send\">Send</a>, Error&gt;<div class=\"where\">where\n    S: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc4315#section-2.1\"><code>UID EXPUNGE</code> command</a> permanently\nremoves all messages that both have [<code>Flag::Deleted</code>] set and have a [<code>Uid</code>] that is\nincluded in the specified sequence set from the currently selected mailbox.  If a message\neither does not have [<code>Flag::Deleted</code>] set or has a [<code>Uid</code>] that is not included in the\nspecified sequence set, it is not affected.</p>\n<p>This command is particularly useful for disconnected use clients. By using <code>uid_expunge</code>\ninstead of [<code>Self::expunge</code>] when resynchronizing with the server, the client can ensure that it\ndoes not inadvertantly remove any messages that have been marked as [<code>Flag::Deleted</code>] by\nother clients between the time that the client was last connected and the time the client\nresynchronizes.</p>\n<p>This command requires that the server supports <a href=\"https://tools.ietf.org/html/rfc4315\">RFC\n4315</a> as indicated by the <code>UIDPLUS</code> capability (see\n[<code>Session::capabilities</code>]). If the server does not support the <code>UIDPLUS</code> capability, the\nclient should fall back to using [<code>Session::store</code>] to temporarily remove [<code>Flag::Deleted</code>]\nfrom messages it does not want to remove, then invoking [<code>Session::expunge</code>].  Finally, the\nclient should use [<code>Session::store</code>] to restore [<code>Flag::Deleted</code>] on the messages in which\nit was temporarily removed.</p>\n<p>Alternatively, the client may fall back to using just [<code>Session::expunge</code>], risking the\nunintended removal of some messages.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.check\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.check\" class=\"fn\">check</a>(&amp;mut self) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.unit.html\">()</a>, Error&gt;</h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc3501#section-6.4.1\"><code>CHECK</code> command</a> requests a\ncheckpoint of the currently selected mailbox.  A checkpoint refers to any\nimplementation-dependent housekeeping associated with the mailbox (e.g., resolving the\nserver’s in-memory state of the mailbox with the state on its disk) that is not normally\nexecuted as part of each command.  A checkpoint MAY take a non-instantaneous amount of real\ntime to complete.  If a server implementation has no such housekeeping considerations,\n[<code>Session::check</code>] is equivalent to [<code>Session::noop</code>].</p>\n<p>There is no guarantee that an <code>EXISTS</code> untagged response will happen as a result of\n<code>CHECK</code>.  [<code>Session::noop</code>] SHOULD be used for new message polling.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.close\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.close\" class=\"fn\">close</a>(&amp;mut self) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.unit.html\">()</a>, Error&gt;</h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc3501#section-6.4.2\"><code>CLOSE</code> command</a> permanently\nremoves all messages that have [<code>Flag::Deleted</code>] set from the currently selected mailbox,\nand returns to the authenticated state from the selected state.  No <code>EXPUNGE</code> responses are\nsent.</p>\n<p>No messages are removed, and no error is given, if the mailbox is selected by\n[<code>Session::examine</code>] or is otherwise selected read-only.</p>\n<p>Even if a mailbox is selected, [<code>Session::select</code>], [<code>Session::examine</code>], or\n[<code>Session::logout</code>] command MAY be issued without previously invoking [<code>Session::close</code>].\n[<code>Session::select</code>], [<code>Session::examine</code>], and [<code>Session::logout</code>] implicitly close the\ncurrently selected mailbox without doing an expunge.  However, when many messages are\ndeleted, a <code>CLOSE-LOGOUT</code> or <code>CLOSE-SELECT</code> sequence is considerably faster than an\n<code>EXPUNGE-LOGOUT</code> or <code>EXPUNGE-SELECT</code> because no <code>EXPUNGE</code> responses (which the client would\nprobably ignore) are sent.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.store\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.store\" class=\"fn\">store</a>&lt;S1, S2&gt;(\n    &amp;mut self,\n    sequence_set: S1,\n    query: S2,\n) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;impl Stream&lt;Item = <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;Fetch, Error&gt;&gt; + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/marker/trait.Send.html\" title=\"trait core::marker::Send\">Send</a>, Error&gt;<div class=\"where\">where\n    S1: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,\n    S2: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc3501#section-6.4.6\"><code>STORE</code> command</a> alters data\nassociated with a message in the mailbox.  Normally, <code>STORE</code> will return the updated value\nof the data with an untagged FETCH response.  A suffix of <code>.SILENT</code> in <code>query</code> prevents the\nuntagged <code>FETCH</code>, and the server assumes that the client has determined the updated value\nitself or does not care about the updated value.</p>\n<p>The currently defined data items that can be stored are:</p>\n<ul>\n<li>\n<p><code>FLAGS &lt;flag list&gt;</code>:</p>\n<p>Replace the flags for the message (other than [<code>Flag::Recent</code>]) with the argument.  The\nnew value of the flags is returned as if a <code>FETCH</code> of those flags was done.</p>\n</li>\n<li>\n<p><code>FLAGS.SILENT &lt;flag list&gt;</code>: Equivalent to <code>FLAGS</code>, but without returning a new value.</p>\n</li>\n<li>\n<p><code>+FLAGS &lt;flag list&gt;</code></p>\n<p>Add the argument to the flags for the message.  The new value of the flags is returned\nas if a <code>FETCH</code> of those flags was done.</p>\n</li>\n<li>\n<p><code>+FLAGS.SILENT &lt;flag list&gt;</code>: Equivalent to <code>+FLAGS</code>, but without returning a new value.</p>\n</li>\n<li>\n<p><code>-FLAGS &lt;flag list&gt;</code></p>\n<p>Remove the argument from the flags for the message.  The new value of the flags is\nreturned as if a <code>FETCH</code> of those flags was done.</p>\n</li>\n<li>\n<p><code>-FLAGS.SILENT &lt;flag list&gt;</code>: Equivalent to <code>-FLAGS</code>, but without returning a new value.</p>\n</li>\n</ul>\n<p>In all cases, <code>&lt;flag list&gt;</code> is a space-separated list enclosed in parentheses.</p>\n<h5 id=\"examples\"><a class=\"doc-anchor\" href=\"#examples\">§</a>Examples</h5>\n<p>Delete a message:</p>\n\n<div class=\"example-wrap\"><pre class=\"rust rust-example-rendered\"><code><span class=\"kw\">use </span>async_imap::{types::Seq, Session, error::Result};\n<span class=\"attr\">#[cfg(feature = <span class=\"string\">\"runtime-async-std\"</span>)]\n</span><span class=\"kw\">use </span>async_std::net::TcpStream;\n<span class=\"attr\">#[cfg(feature = <span class=\"string\">\"runtime-tokio\"</span>)]\n</span><span class=\"kw\">use </span>tokio::net::TcpStream;\n<span class=\"kw\">use </span>futures::TryStreamExt;\n\n<span class=\"kw\">async fn </span>delete(seq: Seq, s: <span class=\"kw-2\">&amp;mut </span>Session&lt;TcpStream&gt;) -&gt; <span class=\"prelude-ty\">Result</span>&lt;()&gt; {\n    <span class=\"kw\">let </span>updates_stream = s.store(<span class=\"macro\">format!</span>(<span class=\"string\">\"{}\"</span>, seq), <span class=\"string\">\"+FLAGS (\\\\Deleted)\"</span>).<span class=\"kw\">await</span><span class=\"question-mark\">?</span>;\n    <span class=\"kw\">let </span>_updates: Vec&lt;<span class=\"kw\">_</span>&gt; = updates_stream.try_collect().<span class=\"kw\">await</span><span class=\"question-mark\">?</span>;\n    s.expunge().<span class=\"kw\">await</span><span class=\"question-mark\">?</span>;\n    <span class=\"prelude-val\">Ok</span>(())\n}</code></pre></div></div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.uid_store\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.uid_store\" class=\"fn\">uid_store</a>&lt;S1, S2&gt;(\n    &amp;mut self,\n    uid_set: S1,\n    query: S2,\n) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;impl Stream&lt;Item = <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;Fetch, Error&gt;&gt; + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/marker/trait.Send.html\" title=\"trait core::marker::Send\">Send</a>, Error&gt;<div class=\"where\">where\n    S1: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,\n    S2: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>Equivalent to [<code>Session::store</code>], except that all identifiers in <code>sequence_set</code> are\n[<code>Uid</code>]s. See also the <a href=\"https://tools.ietf.org/html/rfc3501#section-6.4.8\"><code>UID</code> command</a>.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.copy\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.copy\" class=\"fn\">copy</a>&lt;S1, S2&gt;(\n    &amp;mut self,\n    sequence_set: S1,\n    mailbox_name: S2,\n) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.unit.html\">()</a>, Error&gt;<div class=\"where\">where\n    S1: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,\n    S2: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc3501#section-6.4.7\"><code>COPY</code> command</a> copies the\nspecified message(s) to the end of the specified destination mailbox.  The flags and\ninternal date of the message(s) will generally be preserved, and [<code>Flag::Recent</code>] will\ngenerally be set, in the copy.</p>\n<p>If the <code>COPY</code> command is unsuccessful for any reason, the server restores the destination\nmailbox to its state before the <code>COPY</code> attempt.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.uid_copy\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.uid_copy\" class=\"fn\">uid_copy</a>&lt;S1, S2&gt;(\n    &amp;mut self,\n    uid_set: S1,\n    mailbox_name: S2,\n) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.unit.html\">()</a>, Error&gt;<div class=\"where\">where\n    S1: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,\n    S2: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>Equivalent to [<code>Session::copy</code>], except that all identifiers in <code>sequence_set</code> are\n[<code>Uid</code>]s. See also the <a href=\"https://tools.ietf.org/html/rfc3501#section-6.4.8\"><code>UID</code> command</a>.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.mv\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.mv\" class=\"fn\">mv</a>&lt;S1, S2&gt;(\n    &amp;mut self,\n    sequence_set: S1,\n    mailbox_name: S2,\n) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.unit.html\">()</a>, Error&gt;<div class=\"where\">where\n    S1: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,\n    S2: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc6851#section-3.1\"><code>MOVE</code> command</a> takes two\narguments: a sequence set and a named mailbox. Each message included in the set is moved,\nrather than copied, from the selected (source) mailbox to the named (target) mailbox.</p>\n<p>This means that a new message is created in the target mailbox with a\nnew [<code>Uid</code>], the original message is removed from the source mailbox, and\nit appears to the client as a single action.  This has the same\neffect for each message as this sequence:</p>\n<ol>\n<li>COPY</li>\n<li>STORE +FLAGS.SILENT \\DELETED</li>\n<li>EXPUNGE</li>\n</ol>\n<p>This command requires that the server supports <a href=\"https://tools.ietf.org/html/rfc6851\">RFC\n6851</a> as indicated by the <code>MOVE</code> capability (see\n[<code>Session::capabilities</code>]).</p>\n<p>Although the effect of the <code>MOVE</code> is the same as the preceding steps, the semantics are not\nidentical: The intermediate states produced by those steps do not occur, and the response\ncodes are different.  In particular, though the <code>COPY</code> and <code>EXPUNGE</code> response codes will be\nreturned, response codes for a <code>store</code> will not be generated and [<code>Flag::Deleted</code>] will not\nbe set for any message.</p>\n<p>Because a <code>MOVE</code> applies to a set of messages, it might fail partway through the set.\nRegardless of whether the command is successful in moving the entire set, each individual\nmessage will either be moved or unaffected.  The server will leave each message in a state\nwhere it is in at least one of the source or target mailboxes (no message can be lost or\norphaned).  The server will generally not leave any message in both mailboxes (it would be\nbad for a partial failure to result in a bunch of duplicate messages).  This is true even\nif the server returns with [<code>Error::No</code>].</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.uid_mv\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.uid_mv\" class=\"fn\">uid_mv</a>&lt;S1, S2&gt;(\n    &amp;mut self,\n    uid_set: S1,\n    mailbox_name: S2,\n) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.unit.html\">()</a>, Error&gt;<div class=\"where\">where\n    S1: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,\n    S2: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>Equivalent to [<code>Session::copy</code>], except that all identifiers in <code>sequence_set</code> are\n[<code>Uid</code>]s. See also the <a href=\"https://tools.ietf.org/html/rfc3501#section-6.4.8\"><code>UID</code> command</a>\nand the <a href=\"https://tools.ietf.org/html/rfc6851#section-3.3\">semantics of <code>MOVE</code> and <code>UID MOVE</code></a>.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.list\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.list\" class=\"fn\">list</a>(\n    &amp;mut self,\n    reference_name: <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/option/enum.Option.html\" title=\"enum core::option::Option\">Option</a>&lt;&amp;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,\n    mailbox_pattern: <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/option/enum.Option.html\" title=\"enum core::option::Option\">Option</a>&lt;&amp;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,\n) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;impl Stream&lt;Item = <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;Name, Error&gt;&gt; + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/marker/trait.Send.html\" title=\"trait core::marker::Send\">Send</a>, Error&gt;</h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc3501#section-6.3.8\"><code>LIST</code> command</a> returns a subset of\nnames from the complete set of all names available to the client.  It returns the name\nattributes, hierarchy delimiter, and name of each such name; see [<code>Name</code>] for more detail.</p>\n<p>If <code>reference_name</code> is <code>None</code> (or <code>\"\"</code>), the currently selected mailbox is used.\nThe returned mailbox names must match the supplied <code>mailbox_pattern</code>.  A non-empty\nreference name argument is the name of a mailbox or a level of mailbox hierarchy, and\nindicates the context in which the mailbox name is interpreted.</p>\n<p>If <code>mailbox_pattern</code> is <code>None</code> (or <code>\"\"</code>), it is a special request to return the hierarchy\ndelimiter and the root name of the name given in the reference.  The value returned as the\nroot MAY be the empty string if the reference is non-rooted or is an empty string.  In all\ncases, a hierarchy delimiter (or <code>NIL</code> if there is no hierarchy) is returned.  This permits\na client to get the hierarchy delimiter (or find out that the mailbox names are flat) even\nwhen no mailboxes by that name currently exist.</p>\n<p>The reference and mailbox name arguments are interpreted into a canonical form that\nrepresents an unambiguous left-to-right hierarchy.  The returned mailbox names will be in\nthe interpreted form.</p>\n<p>The character <code>*</code> is a wildcard, and matches zero or more characters at this position.  The\ncharacter <code>%</code> is similar to <code>*</code>, but it does not match a hierarchy delimiter.  If the <code>%</code>\nwildcard is the last character of a mailbox name argument, matching levels of hierarchy are\nalso returned.  If these levels of hierarchy are not also selectable mailboxes, they are\nreturned with [<code>NameAttribute::NoSelect</code>].</p>\n<p>The special name <code>INBOX</code> is included if <code>INBOX</code> is supported by this server for this user\nand if the uppercase string <code>INBOX</code> matches the interpreted reference and mailbox name\narguments with wildcards.  The criteria for omitting <code>INBOX</code> is whether <code>SELECT INBOX</code> will\nreturn failure; it is not relevant whether the user’s real <code>INBOX</code> resides on this or some\nother server.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.lsub\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.lsub\" class=\"fn\">lsub</a>(\n    &amp;mut self,\n    reference_name: <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/option/enum.Option.html\" title=\"enum core::option::Option\">Option</a>&lt;&amp;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,\n    mailbox_pattern: <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/option/enum.Option.html\" title=\"enum core::option::Option\">Option</a>&lt;&amp;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,\n) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;impl Stream&lt;Item = <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;Name, Error&gt;&gt; + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/marker/trait.Send.html\" title=\"trait core::marker::Send\">Send</a>, Error&gt;</h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc3501#section-6.3.9\"><code>LSUB</code> command</a> returns a subset of\nnames from the set of names that the user has declared as being “active” or “subscribed”.\nThe arguments to this method the same as for [<code>Session::list</code>].</p>\n<p>The returned [<code>Name</code>]s MAY contain different mailbox flags from response to\n[<code>Session::list</code>].  If this should happen, the flags returned by [<code>Session::list</code>] are\nconsidered more authoritative.</p>\n<p>A special situation occurs when invoking <code>lsub</code> with the <code>%</code> wildcard. Consider what\nhappens if <code>foo/bar</code> (with a hierarchy delimiter of <code>/</code>) is subscribed but <code>foo</code> is not.  A\n<code>%</code> wildcard to <code>lsub</code> must return <code>foo</code>, not <code>foo/bar</code>, and it will be flagged with\n[<code>NameAttribute::NoSelect</code>].</p>\n<p>The server will not unilaterally remove an existing mailbox name from the subscription list\neven if a mailbox by that name no longer exists.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.status\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.status\" class=\"fn\">status</a>&lt;S1, S2&gt;(\n    &amp;mut self,\n    mailbox_name: S1,\n    data_items: S2,\n) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;Mailbox, Error&gt;<div class=\"where\">where\n    S1: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,\n    S2: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc3501#section-6.3.10\"><code>STATUS</code> command</a> requests the\nstatus of the indicated mailbox. It does not change the currently selected mailbox, nor\ndoes it affect the state of any messages in the queried mailbox (in particular, <code>status</code>\nwill not cause messages to lose [<code>Flag::Recent</code>]).</p>\n<p><code>status</code> provides an alternative to opening a second [<code>Session</code>] and using\n[<code>Session::examine</code>] on a mailbox to query that mailbox’s status without deselecting the\ncurrent mailbox in the first <code>Session</code>.</p>\n<p>Unlike [<code>Session::list</code>], <code>status</code> is not guaranteed to be fast in its response.  Under\ncertain circumstances, it can be quite slow.  In some implementations, the server is\nobliged to open the mailbox read-only internally to obtain certain status information.\nAlso unlike [<code>Session::list</code>], <code>status</code> does not accept wildcards.</p>\n<blockquote>\n<p>Note: <code>status</code> is intended to access the status of mailboxes other than the currently\nselected mailbox.  Because <code>status</code> can cause the mailbox to be opened internally, and\nbecause this information is available by other means on the selected mailbox, <code>status</code>\nSHOULD NOT be used on the currently selected mailbox.</p>\n</blockquote>\n<p>The STATUS command MUST NOT be used as a “check for new messages in the selected mailbox”\noperation (refer to sections <a href=\"https://tools.ietf.org/html/rfc3501#section-7\">7</a>,\n<a href=\"https://tools.ietf.org/html/rfc3501#section-7.3.1\">7.3.1</a>, and\n<a href=\"https://tools.ietf.org/html/rfc3501#section-7.3.2\">7.3.2</a> for more information about the\nproper method for new message checking).</p>\n<p>The currently defined status data items that can be requested are:</p>\n<ul>\n<li><code>MESSAGES</code>: The number of messages in the mailbox.</li>\n<li><code>RECENT</code>: The number of messages with [<code>Flag::Recent</code>] set.</li>\n<li><code>UIDNEXT</code>: The next [<code>Uid</code>] of the mailbox.</li>\n<li><code>UIDVALIDITY</code>: The unique identifier validity value of the mailbox (see [<code>Uid</code>]).</li>\n<li><code>UNSEEN</code>: The number of messages which do not have [<code>Flag::Seen</code>] set.</li>\n</ul>\n<p><code>data_items</code> is a space-separated list enclosed in parentheses.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.idle\" class=\"method\"><h4 class=\"code-header\">pub fn <a href=\"#method.idle\" class=\"fn\">idle</a>(self) -&gt; Handle&lt;T&gt;</h4></section></summary><div class=\"docblock\"><p>This method returns a handle that lets you use the <a href=\"https://tools.ietf.org/html/rfc2177#section-3\"><code>IDLE</code>\ncommand</a> to listen for changes to the\ncurrently selected mailbox.</p>\n<p>It’s often more desirable to have the server transmit updates to the client in real time.\nThis allows a user to see new mail immediately.  It also helps some real-time applications\nbased on IMAP, which might otherwise need to poll extremely often (such as every few\nseconds).  While the spec actually does allow a server to push <code>EXISTS</code> responses\naysynchronously, a client can’t expect this behaviour and must poll.  This method provides\nyou with such a mechanism.</p>\n<p><code>idle</code> may be used with any server that returns <code>IDLE</code> as one of the supported capabilities\n(see [<code>Session::capabilities</code>]). If the server does not advertise the <code>IDLE</code> capability,\nthe client MUST NOT use <code>idle</code> and must instead poll for mailbox updates.  In particular,\nthe client MUST continue to be able to accept unsolicited untagged responses to ANY\ncommand, as specified in the base IMAP specification.</p>\n<p>See [<code>extensions::idle::Handle</code>] for details.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.append\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.append\" class=\"fn\">append</a>(\n    &amp;mut self,\n    mailbox: impl <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,\n    flags: <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/option/enum.Option.html\" title=\"enum core::option::Option\">Option</a>&lt;&amp;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,\n    internaldate: <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/option/enum.Option.html\" title=\"enum core::option::Option\">Option</a>&lt;&amp;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,\n    content: impl <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;[<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.u8.html\">u8</a>]&gt;,\n) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.unit.html\">()</a>, Error&gt;</h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc3501#section-6.3.11\"><code>APPEND</code> command</a> appends\n<code>content</code> as a new message to the end of the specified destination <code>mailbox</code>.  This\nargument SHOULD be in the format of an <a href=\"https://tools.ietf.org/html/rfc2822\">RFC-2822</a>\nmessage.</p>\n<blockquote>\n<p>Note: There MAY be exceptions, e.g., draft messages, in which required RFC-2822 header\nlines are omitted in the message literal argument to <code>append</code>.  The full implications of\ndoing so MUST be understood and carefully weighed.</p>\n</blockquote>\n<p>If the append is unsuccessful for any reason, the mailbox is restored to its state before\nthe append attempt; no partial appending will happen.</p>\n<p>If the destination <code>mailbox</code> does not exist, the server returns an error, and does not\nautomatically create the mailbox.</p>\n<p>If the mailbox is currently selected, the normal new message actions will generally occur.\nSpecifically, the server will generally notify the client immediately via an untagged\n<code>EXISTS</code> response.  If the server does not do so, the client MAY issue a <code>NOOP</code> command (or\nfailing that, a <code>CHECK</code> command) after one or more <code>APPEND</code> commands.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.search\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.search\" class=\"fn\">search</a>&lt;S&gt;(&amp;mut self, query: S) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"struct\" href=\"https://doc.rust-lang.org/1.96.1/std/collections/hash/set/struct.HashSet.html\" title=\"struct std::collections::hash::set::HashSet\">HashSet</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.u32.html\">u32</a>&gt;, Error&gt;<div class=\"where\">where\n    S: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc3501#section-6.4.4\"><code>SEARCH</code> command</a> searches the\nmailbox for messages that match the given <code>query</code>.  <code>query</code> consist of one or more search\nkeys separated by spaces.  The response from the server contains a listing of [<code>Seq</code>]s\ncorresponding to those messages that match the searching criteria.</p>\n<p>When multiple search keys are specified, the result is the intersection of all the messages\nthat match those keys.  Or, in other words, only messages that match <em>all</em> the keys. For\nexample, the criteria</p>\n<div class=\"example-wrap\"><pre class=\"language-text\"><code>DELETED FROM &quot;SMITH&quot; SINCE 1-Feb-1994</code></pre></div>\n<p>refers to all deleted messages from Smith that were placed in the mailbox since February 1,\n1994.  A search key can also be a parenthesized list of one or more search keys (e.g., for\nuse with the <code>OR</code> and <code>NOT</code> keys).</p>\n<p>In all search keys that use strings, a message matches the key if the string is a substring\nof the field.  The matching is case-insensitive.</p>\n<p>Below is a selection of common search keys.  The full list can be found in the\nspecification of the <a href=\"https://tools.ietf.org/html/rfc3501#section-6.4.4\"><code>SEARCH command</code></a>.</p>\n<ul>\n<li>\n<p><code>NEW</code>: Messages that have [<code>Flag::Recent</code>] set but not [<code>Flag::Seen</code>]. This is functionally equivalent to <code>(RECENT UNSEEN)</code>.</p>\n</li>\n<li>\n<p><code>OLD</code>: Messages that do not have [<code>Flag::Recent</code>] set.  This is functionally equivalent to <code>NOT RECENT</code> (as opposed to <code>NOT NEW</code>).</p>\n</li>\n<li>\n<p><code>RECENT</code>: Messages that have [<code>Flag::Recent</code>] set.</p>\n</li>\n<li>\n<p><code>ANSWERED</code>: Messages with [<code>Flag::Answered</code>] set.</p>\n</li>\n<li>\n<p><code>DELETED</code>: Messages with [<code>Flag::Deleted</code>] set.</p>\n</li>\n<li>\n<p><code>DRAFT</code>: Messages with [<code>Flag::Draft</code>] set.</p>\n</li>\n<li>\n<p><code>FLAGGED</code>: Messages with [<code>Flag::Flagged</code>] set.</p>\n</li>\n<li>\n<p><code>SEEN</code>: Messages that have [<code>Flag::Seen</code>] set.</p>\n</li>\n<li>\n<p><code>&lt;sequence set&gt;</code>: Messages with message sequence numbers corresponding to the specified message sequence number set.</p>\n</li>\n<li>\n<p><code>UID &lt;sequence set&gt;</code>: Messages with [<code>Uid</code>] corresponding to the specified unique identifier set.  Sequence set ranges are permitted.</p>\n</li>\n<li>\n<p><code>SUBJECT &lt;string&gt;</code>: Messages that contain the specified string in the envelope structure’s <code>SUBJECT</code> field.</p>\n</li>\n<li>\n<p><code>BODY &lt;string&gt;</code>: Messages that contain the specified string in the body of the message.</p>\n</li>\n<li>\n<p><code>FROM &lt;string&gt;</code>: Messages that contain the specified string in the envelope structure’s <code>FROM</code> field.</p>\n</li>\n<li>\n<p><code>TO &lt;string&gt;</code>: Messages that contain the specified string in the envelope structure’s <code>TO</code> field.</p>\n</li>\n<li>\n<p><code>NOT &lt;search-key&gt;</code>: Messages that do not match the specified search key.</p>\n</li>\n<li>\n<p><code>OR &lt;search-key1&gt; &lt;search-key2&gt;</code>: Messages that match either search key.</p>\n</li>\n<li>\n<p><code>BEFORE &lt;date&gt;</code>: Messages whose internal date (disregarding time and timezone) is earlier than the specified date.</p>\n</li>\n<li>\n<p><code>SINCE &lt;date&gt;</code>: Messages whose internal date (disregarding time and timezone) is within or later than the specified date.</p>\n</li>\n</ul>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.uid_search\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.uid_search\" class=\"fn\">uid_search</a>&lt;S&gt;(&amp;mut self, query: S) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"struct\" href=\"https://doc.rust-lang.org/1.96.1/std/collections/hash/set/struct.HashSet.html\" title=\"struct std::collections::hash::set::HashSet\">HashSet</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.u32.html\">u32</a>&gt;, Error&gt;<div class=\"where\">where\n    S: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>Equivalent to [<code>Session::search</code>], except that the returned identifiers\nare [<code>Uid</code>] instead of [<code>Seq</code>]. See also the <a href=\"https://tools.ietf.org/html/rfc3501#section-6.4.8\"><code>UID</code>\ncommand</a>.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.get_quota\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.get_quota\" class=\"fn\">get_quota</a>(&amp;mut self, quota_root: &amp;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;Quota, Error&gt;</h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc2087#section-4.2\"><code>GETQUOTA</code> command</a></p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.get_quota_root\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.get_quota_root\" class=\"fn\">get_quota_root</a>(\n    &amp;mut self,\n    mailbox_name: &amp;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>,\n) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;(<a class=\"struct\" href=\"https://doc.rust-lang.org/1.96.1/alloc/vec/struct.Vec.html\" title=\"struct alloc::vec::Vec\">Vec</a>&lt;QuotaRoot&gt;, <a class=\"struct\" href=\"https://doc.rust-lang.org/1.96.1/alloc/vec/struct.Vec.html\" title=\"struct alloc::vec::Vec\">Vec</a>&lt;Quota&gt;), Error&gt;</h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://tools.ietf.org/html/rfc2087#section-4.3\"><code>GETQUOTAROOT</code> command</a></p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.get_metadata\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.get_metadata\" class=\"fn\">get_metadata</a>(\n    &amp;mut self,\n    mailbox_name: &amp;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>,\n    options: &amp;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>,\n    entry_specifier: &amp;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>,\n) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"struct\" href=\"https://doc.rust-lang.org/1.96.1/alloc/vec/struct.Vec.html\" title=\"struct alloc::vec::Vec\">Vec</a>&lt;Metadata&gt;, Error&gt;</h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://datatracker.ietf.org/doc/html/rfc5464.html#section-4.2\"><code>GETMETADATA</code> command</a></p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.id\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.id\" class=\"fn\">id</a>(\n    &amp;mut self,\n    identification: impl <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/iter/traits/collect/trait.IntoIterator.html\" title=\"trait core::iter::traits::collect::IntoIterator\">IntoIterator</a>&lt;Item = (&amp;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>, <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/option/enum.Option.html\" title=\"enum core::option::Option\">Option</a>&lt;&amp;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;)&gt;,\n) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/option/enum.Option.html\" title=\"enum core::option::Option\">Option</a>&lt;<a class=\"struct\" href=\"https://doc.rust-lang.org/1.96.1/std/collections/hash/map/struct.HashMap.html\" title=\"struct std::collections::hash::map::HashMap\">HashMap</a>&lt;<a class=\"struct\" href=\"https://doc.rust-lang.org/1.96.1/alloc/string/struct.String.html\" title=\"struct alloc::string::String\">String</a>, <a class=\"struct\" href=\"https://doc.rust-lang.org/1.96.1/alloc/string/struct.String.html\" title=\"struct alloc::string::String\">String</a>&gt;&gt;, Error&gt;</h4></section></summary><div class=\"docblock\"><p>The <a href=\"https://datatracker.ietf.org/doc/html/rfc2971\"><code>ID</code> command</a></p>\n<p><code>identification</code> is an iterable sequence of pairs such as <code>(\"name\", Some(\"MyMailClient\"))</code>.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.id_nil\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.id_nil\" class=\"fn\">id_nil</a>(&amp;mut self) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/option/enum.Option.html\" title=\"enum core::option::Option\">Option</a>&lt;<a class=\"struct\" href=\"https://doc.rust-lang.org/1.96.1/std/collections/hash/map/struct.HashMap.html\" title=\"struct std::collections::hash::map::HashMap\">HashMap</a>&lt;<a class=\"struct\" href=\"https://doc.rust-lang.org/1.96.1/alloc/string/struct.String.html\" title=\"struct alloc::string::String\">String</a>, <a class=\"struct\" href=\"https://doc.rust-lang.org/1.96.1/alloc/string/struct.String.html\" title=\"struct alloc::string::String\">String</a>&gt;&gt;, Error&gt;</h4></section></summary><div class=\"docblock\"><p>Similar to <code>id</code>, but don’t identify ourselves.</p>\n<p>Sends <code>ID NIL</code> command and returns server response.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.run_command_and_check_ok\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.run_command_and_check_ok\" class=\"fn\">run_command_and_check_ok</a>&lt;S&gt;(\n    &amp;mut self,\n    command: S,\n) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.unit.html\">()</a>, Error&gt;<div class=\"where\">where\n    S: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>Runs a command and checks if it returns OK.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.run_command\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.run_command\" class=\"fn\">run_command</a>&lt;S&gt;(&amp;mut self, command: S) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;RequestId, Error&gt;<div class=\"where\">where\n    S: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>Runs any command passed to it.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.run_command_untagged\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.run_command_untagged\" class=\"fn\">run_command_untagged</a>&lt;S&gt;(&amp;mut self, command: S) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.unit.html\">()</a>, Error&gt;<div class=\"where\">where\n    S: <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/convert/trait.AsRef.html\" title=\"trait core::convert::AsRef\">AsRef</a>&lt;<a class=\"primitive\" href=\"https://doc.rust-lang.org/1.96.1/std/primitive.str.html\">str</a>&gt;,</div></h4></section></summary><div class=\"docblock\"><p>Runs an arbitrary command, without adding a tag to it.</p>\n</div></details><details class=\"toggle method-toggle\" open><summary><section id=\"method.read_response\" class=\"method\"><h4 class=\"code-header\">pub async fn <a href=\"#method.read_response\" class=\"fn\">read_response</a>(&amp;mut self) -&gt; <a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/result/enum.Result.html\" title=\"enum core::result::Result\">Result</a>&lt;<a class=\"enum\" href=\"https://doc.rust-lang.org/1.96.1/core/option/enum.Option.html\" title=\"enum core::option::Option\">Option</a>&lt;ResponseData&gt;, <a class=\"struct\" href=\"https://doc.rust-lang.org/1.96.1/std/io/error/struct.Error.html\" title=\"struct std::io::error::Error\">Error</a>&gt;</h4></section></summary><div class=\"docblock\"><p>Read the next response on the connection.</p>\n</div></details></div></details>",0,"zeroclaw_tools::email_imap::ImapSession"],["<section id=\"impl-Unpin-for-Session%3CT%3E\" class=\"impl\"><a href=\"#impl-Unpin-for-Session%3CT%3E\" class=\"anchor\">§</a><h3 class=\"code-header\">impl&lt;T&gt; <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/marker/trait.Unpin.html\" title=\"trait core::marker::Unpin\">Unpin</a> for Session&lt;T&gt;<div class=\"where\">where\n    T: AsyncRead + AsyncWrite + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/marker/trait.Unpin.html\" title=\"trait core::marker::Unpin\">Unpin</a> + <a class=\"trait\" href=\"https://doc.rust-lang.org/1.96.1/core/fmt/trait.Debug.html\" title=\"trait core::fmt::Debug\">Debug</a>,</div></h3></section>","Unpin","zeroclaw_tools::email_imap::ImapSession"]]]]);
    if (window.register_type_impls) {
        window.register_type_impls(type_impls);
    } else {
        window.pending_type_impls = type_impls;
    }
})()
